package com.community.news.lambda;

public class ImageResizeEvent {
    private String postId;
    private String originalImageKey;
    private String timestamp;

    public String getPostId() {
        return postId;
    }

    public void setPostId(String postId) {
        this.postId = postId;
    }

    public String getOriginalImageKey() {
        return originalImageKey;
    }

    public void setOriginalImageKey(String originalImageKey) {
        this.originalImageKey = originalImageKey;
    }

    public String getTimestamp() {
        return timestamp;
    }

    public void setTimestamp(String timestamp) {
        this.timestamp = timestamp;
    }
}

package com.community.news.lambda;

import com.amazonaws.services.lambda.runtime.Context;
import com.amazonaws.services.lambda.runtime.RequestHandler;
import com.amazonaws.services.lambda.runtime.events.SQSEvent;
import com.fasterxml.jackson.databind.ObjectMapper;
import software.amazon.awssdk.auth.credentials.DefaultCredentialsProvider;
import software.amazon.awssdk.regions.Region;
import software.amazon.awssdk.services.dynamodb.DynamoDbClient;
import software.amazon.awssdk.services.dynamodb.model.AttributeValue;
import software.amazon.awssdk.services.dynamodb.model.UpdateItemRequest;
import software.amazon.awssdk.services.s3.S3Client;
import software.amazon.awssdk.services.s3.model.GetObjectRequest;
import software.amazon.awssdk.services.s3.model.GetObjectResponse;
import software.amazon.awssdk.services.s3.model.PutObjectRequest;
import software.amazon.awssdk.core.ResponseInputStream;
import software.amazon.awssdk.core.sync.RequestBody;

import java.net.URI;
import java.util.HashMap;
import java.util.Map;

public class ImageResizeHandler implements RequestHandler<SQSEvent, Map<String, Object>> {

    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
    private static final String BUCKET = env("S3_BUCKET", "community-news-poze-2026");
    private static final String TABLE = env("DYNAMODB_TABLE", "NewsPosts");
    private static final String REGION = env("AWS_REGION", "eu-north-1");
    private static final String ENDPOINT = System.getenv("AWS_ENDPOINT_URL");

    private final S3Client s3Client;
    private final DynamoDbClient dynamoDbClient;

    public ImageResizeHandler() {
        this.s3Client = buildS3Client();
        this.dynamoDbClient = buildDynamoClient();
    }

    @Override
    public Map<String, Object> handleRequest(SQSEvent event, Context context) {
        int processed = 0;
        int errors = 0;

        for (SQSEvent.SQSMessage message : event.getRecords()) {
            try {
                ImageResizeEvent resizeEvent = OBJECT_MAPPER.readValue(message.getBody(), ImageResizeEvent.class);
                String postId = resizeEvent.getPostId();
                String originalKey = resizeEvent.getOriginalImageKey();
                String timestamp = resizeEvent.getTimestamp();

                if (postId == null || originalKey == null || timestamp == null) {
                    throw new IllegalArgumentException("postId, originalImageKey, and timestamp are required");
                }

                GetObjectRequest getObjectRequest = GetObjectRequest.builder()
                        .bucket(BUCKET)
                        .key(originalKey)
                        .build();

                byte[] originalBytes;
                String contentType;
                try (ResponseInputStream<GetObjectResponse> response = s3Client.getObject(getObjectRequest)) {
                    originalBytes = response.readAllBytes();
                    contentType = response.response().contentType();
                }

                String format = resolveFormat(originalKey, contentType);
                byte[] thumbnailBytes = ThumbnailGenerator.createThumbnail(originalBytes, format);

                String thumbnailKey = buildThumbnailKey(postId, originalKey);
                PutObjectRequest putObjectRequest = PutObjectRequest.builder()
                        .bucket(BUCKET)
                        .key(thumbnailKey)
                        .contentType(contentType == null ? "image/jpeg" : contentType)
                        .build();

                s3Client.putObject(putObjectRequest, RequestBody.fromBytes(thumbnailBytes));

                Map<String, AttributeValue> key = new HashMap<>();
                key.put("postId", AttributeValue.builder().s(postId).build());
                key.put("timestamp", AttributeValue.builder().s(timestamp).build());

                Map<String, AttributeValue> values = new HashMap<>();
                values.put(":thumb", AttributeValue.builder().s(thumbnailKey).build());

                UpdateItemRequest updateRequest = UpdateItemRequest.builder()
                        .tableName(TABLE)
                        .key(key)
                        .updateExpression("SET thumbnailImageUrl = :thumb")
                        .expressionAttributeValues(values)
                        .build();

                dynamoDbClient.updateItem(updateRequest);
                processed++;
            } catch (Exception ex) {
                errors++;
                if (context != null && context.getLogger() != null) {
                    context.getLogger().log("Failed to process SQS message: " + ex.getMessage());
                }
            }
        }

        Map<String, Object> result = new HashMap<>();
        result.put("processed", processed);
        result.put("errors", errors);
        return result;
    }

    private static String buildThumbnailKey(String postId, String originalKey) {
        String filename = originalKey.substring(originalKey.lastIndexOf('/') + 1);
        return "thumbnails/" + postId + "-" + filename;
    }

    private static String resolveFormat(String key, String contentType) {
        if (contentType != null) {
            if (contentType.contains("png")) {
                return "png";
            }
            if (contentType.contains("jpeg") || contentType.contains("jpg")) {
                return "jpg";
            }
        }
        String ext = key.substring(key.lastIndexOf('.') + 1).toLowerCase();
        if (ext.equals("png")) {
            return "png";
        }
        return "jpg";
    }

    private static String env(String key, String defaultValue) {
        String value = System.getenv(key);
        return value == null || value.isBlank() ? defaultValue : value;
    }

    private static S3Client buildS3Client() {
        S3Client.Builder builder = S3Client.builder()
                .region(Region.of(REGION))
                .credentialsProvider(DefaultCredentialsProvider.create());

        if (ENDPOINT != null && !ENDPOINT.isBlank()) {
            builder.endpointOverride(URI.create(ENDPOINT));
        }

        return builder.build();
    }

    private static DynamoDbClient buildDynamoClient() {
        DynamoDbClient.Builder builder = DynamoDbClient.builder()
                .region(Region.of(REGION))
                .credentialsProvider(DefaultCredentialsProvider.create());

        if (ENDPOINT != null && !ENDPOINT.isBlank()) {
            builder.endpointOverride(URI.create(ENDPOINT));
        }

        return builder.build();
    }
}

package com.community.news.lambda;

import javax.imageio.ImageIO;
import java.awt.Graphics2D;
import java.awt.Image;
import java.awt.RenderingHints;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;

public final class ThumbnailGenerator {
    private ThumbnailGenerator() {
    }

    public static byte[] createThumbnail(byte[] source, String format) throws IOException {
        System.setProperty("java.awt.headless", "true");

        BufferedImage input = ImageIO.read(new ByteArrayInputStream(source));
        if (input == null) {
            throw new IOException("Unsupported image format");
        }

        int targetSize = 128;
        int width = input.getWidth();
        int height = input.getHeight();
        double scale = Math.min((double) targetSize / width, (double) targetSize / height);
        int newWidth = Math.max(1, (int) Math.round(width * scale));
        int newHeight = Math.max(1, (int) Math.round(height * scale));

        Image scaled = input.getScaledInstance(newWidth, newHeight, Image.SCALE_SMOOTH);
        BufferedImage outputImage = new BufferedImage(newWidth, newHeight, BufferedImage.TYPE_INT_RGB);
        Graphics2D graphics = outputImage.createGraphics();
        graphics.setRenderingHint(RenderingHints.KEY_INTERPOLATION, RenderingHints.VALUE_INTERPOLATION_BILINEAR);
        graphics.drawImage(scaled, 0, 0, null);
        graphics.dispose();

        String safeFormat = format == null || format.isBlank() ? "jpg" : format;
        ByteArrayOutputStream output = new ByteArrayOutputStream();
        ImageIO.write(outputImage, safeFormat, output);
        return output.toByteArray();
    }
}

package com.community.news.lambda;

import javax.imageio.ImageIO;
import java.awt.Color;
import java.awt.Graphics2D;
import java.awt.image.BufferedImage;
import java.io.ByteArrayOutputStream;
import java.io.File;
import java.io.IOException;

public class LocalResizeTest {
    public static void main(String[] args) throws IOException {
        BufferedImage image = new BufferedImage(512, 256, BufferedImage.TYPE_INT_RGB);
        Graphics2D graphics = image.createGraphics();
        graphics.setColor(new Color(120, 180, 240));
        graphics.fillRect(0, 0, 512, 256);
        graphics.dispose();

        ByteArrayOutputStream output = new ByteArrayOutputStream();
        ImageIO.write(image, "jpg", output);

        byte[] thumbnail = ThumbnailGenerator.createThumbnail(output.toByteArray(), "jpg");
        File outFile = new File("thumb_test.jpg");
        ImageIO.write(ImageIO.read(new java.io.ByteArrayInputStream(thumbnail)), "jpg", outFile);

        System.out.println("Wrote " + outFile.getAbsolutePath());
    }
}
